import{_ as t,o as e,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"F13: 資本支出效能與股利防禦","description":"","frontmatter":{},"headers":[],"relativePath":"32Ｑ題本＿重要/財務組/F13_資本支出效能與股利防禦_投資研究員.md","filePath":"32Ｑ題本＿重要/財務組/F13_資本支出效能與股利防禦_投資研究員.md"}'),i={name:"32Ｑ題本＿重要/財務組/F13_資本支出效能與股利防禦_投資研究員.md"};function a(l,o,s,c,d,g){return e(),n("div",null,[...o[0]||(o[0]=[r('<blockquote><p>[MANDATORY] 執行前必須完整讀取 [03_審計專家_任務執行與技術協議.md](file:///Users/kaipro/.openclaw/skills/NEW_Deep32Q/03_審計專家_任務執行與技術協議.md) 並在思維區宣告對位。</p></blockquote><h1 id="f13-資本支出效能與股利防禦" tabindex="-1">F13: 資本支出效能與股利防禦 <a class="header-anchor" href="#f13-資本支出效能與股利防禦" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦&quot;">​</a></h1><ul><li><strong>本題 ID：</strong> Q-F13</li><li><strong>題目：</strong> 資本支出 (CapEx) 的投入效能為何？自由現金流 (FCF) 是否足以支撐其股利政策？是否存在「借債配息」之虛耗現象？</li><li><strong>推薦專家：</strong> 投資研究員 (<code>finance-investment-researcher</code>)</li><li><strong>推薦理由：</strong> 專精於「資本配置 (Capital Allocation)」與「股東回報模型」。擅長分析企業在擴張與分紅之間的平衡藝術，能識別企業是在進行「高回報投資」，還是在進行「無效的資本虛耗」，為長期持有的價值提供安全校準。</li><li><strong>意圖：</strong> 執行「資本支出回報與財務防禦審計」。透過分析 CapEx 成長與營收/利潤成長的階差，判定擴產效能；透過精算 FCF，判定股利支付的安全性，識別是否存在掏空公司資產以迎合市場分紅預期的風險。</li><li><strong>數據路徑與優先權 (Data Source Waterfall)：</strong><ol><li><strong>【核心數據基石：FinMind】</strong>：調用 <code>TaiwanStockCashFlowsStatement</code> 提取 <code>CapitalExpenditures</code>、<code>CashFlowsFromOperatingActivities</code> 與 <code>CashDividendPaid</code>。</li><li><strong>【外部事實確認：優分析/財經媒體 (cnYES/MOPS)】</strong>：獲取歷年「股利發放率 (Payout Ratio)」與「殖利率」趨勢。</li><li><strong>【穿透校準：Annual Report (年報)】</strong>：查閱「現金流量表附註」與「股利政策說明」。</li></ol></li><li><strong>邏輯：</strong> 執行「CapEx 成長階差分析」——計算 <code>(營收成長率 / CapEx 成長率)</code>；執行「現金流覆蓋測試」——計算 <code>FCF / 總配息金額</code>。</li><li><strong>來源：</strong> <code>FinMind</code></li></ul><h2 id="🛠️-工作流程-按順序執行-不得跳過" tabindex="-1">🛠️ 工作流程（按順序執行，不得跳過） <a class="header-anchor" href="#🛠️-工作流程-按順序執行-不得跳過" aria-label="Permalink to &quot;🛠️ 工作流程（按順序執行，不得跳過）&quot;">​</a></h2><ol><li><strong>跑工具</strong>：<code>python3 財務分析工具.py capex_efficiency [股號]</code> → 取得 CapEx、FCF</li><li><strong>取股利</strong>：<code>python3 數據採集器.py dividend [股號]</code> → 抓現金股利</li><li><strong>判讀</strong>：FCF/股利 &lt;1 = 借債配息警訊；CapEx/營收比 &gt;20% = 擴張期</li><li><strong>年報補充</strong>：用 <code>pdf</code> 工具提取「股利政策」</li><li><strong>撰寫報告</strong>：依下方回答模板結構產出</li></ol><p>⚠️ <strong>常見陷阱</strong>：①答詢詳解 ≥200 字、專家評析 ≥200 字；②空頭視角 ≥2 個；③FCF 要含 CapEx 計算</p><h2 id="具體化思考點-智能體強制執行指令" tabindex="-1">具體化思考點 (智能體強制執行指令) <a class="header-anchor" href="#具體化思考點-智能體強制執行指令" aria-label="Permalink to &quot;具體化思考點 (智能體強制執行指令)&quot;">​</a></h2><ul><li><strong>【資本支出效能實測】</strong>：智慧體<strong>必須</strong>列出最近 3 年的 CapEx 金額與次年營收成長的連動性。嚴禁在未計算回報率前給予「積極擴產」之正面評價。</li><li><strong>【配息含金量審核】</strong>：智慧體必須計算 <code>自由現金流 (CFO - CapEx)</code>。若自由現金流為負但仍發放高額股利，必須強制發出「損害長期競爭力」或「借債發薪」之嚴厲警訊。</li><li><strong>【股利穩定性測試】</strong>：判定在利潤下滑 20% 的情境下，既有的股利政策是否具備「防禦韌性」。</li><li><strong>【描述指標】</strong>：絕對禁用「配息大方」、「投入巨大」。必須量化為具體的「FCF 覆蓋倍數」、「CapEx 回報係數」與「資產支出率 %」。</li></ul><hr><h2 id="回答模板與注意事項" tabindex="-1">回答模板與注意事項 <a class="header-anchor" href="#回答模板與注意事項" aria-label="Permalink to &quot;回答模板與注意事項&quot;">​</a></h2><h4 id="【f13-專家答詢】投資研究員-finance-investment-researcher" tabindex="-1">【F13 專家答詢】投資研究員 (finance-investment-researcher) <a class="header-anchor" href="#【f13-專家答詢】投資研究員-finance-investment-researcher" aria-label="Permalink to &quot;【F13 專家答詢】投資研究員 (finance-investment-researcher)&quot;">​</a></h4><ul><li><strong>【專家直斷】品質要求</strong>：須採「支出效能+配息安全性」結構（例：CapEx 回報率為 X，FCF 覆蓋率為 Y，判定 [投資高效/無效]，股利政策屬 [穩健/虛耗] 型態）。</li><li><strong>【診斷評級】評分準則</strong>： <ul><li><strong>S (優)</strong>：投資回報顯著（營收增幅高於支出增幅），且 FCF 極其充裕，足以同時支撐擴產與優渥的分紅，資本配置處於「正向循環」極致。</li><li><strong>A (良)</strong>：擴產節奏合理，分紅由營運現金流支撐，財務體質健康。</li><li><strong>B (持平)</strong>：CapEx 巨大但營收停滯，或分紅高度依賴舉債/處分資產，顯示資本配置失能，長期價值具備「崩塌風險」。</li><li><strong>【答詢詳解】解析深度</strong>：必須嚴格遵守 Fact-First 原則，確保每一段論述都有物理數字實體支撐，嚴禁脫離數據空泛推論。</li><li><strong>【專家評析】核心洞察</strong>：必須採「多空雙向」結構——同時提供空方（利空風險）與多方（機會/利多）觀點，每方至少 2 點具體事實，最後綜合權衡。</li></ul></li><li><strong>【證據來源】數據溯源</strong>：必須精確標註 FinMind <code>cashflow</code> 數據項與計算過程。</li></ul>',12)])])}const h=t(i,[["render",a]]);export{p as __pageData,h as default};
